--
-- Table structure for table `duty_record`
--

DROP TABLE IF EXISTS `duty_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `duty_record` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '值班记录ID',
  `assignment_id` bigint NOT NULL COMMENT '关联值班安排ID',
  `employee_id` bigint NOT NULL COMMENT '值班人员ID',
  `check_in_time` datetime DEFAULT NULL COMMENT '签到时间',
  `check_out_time` datetime DEFAULT NULL COMMENT '签退时间',
  `duty_status` tinyint DEFAULT '1' COMMENT '值班状态：1正常，2迟到，3早退，4缺勤，5请假',
  `check_in_remark` varchar(200) DEFAULT NULL COMMENT '签到备注',
  `check_out_remark` varchar(200) DEFAULT NULL COMMENT '签退备注',
  `overtime_hours` decimal(5,2) DEFAULT '0.00' COMMENT '加班时长',
  `approval_status` varchar(20) DEFAULT 'pending' COMMENT '审批状态：pending待审批，approved已审批，rejected已拒绝',
  `manager_remark` varchar(200) DEFAULT NULL COMMENT '经理备注',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `substitute_employee_id` bigint DEFAULT NULL COMMENT '替补人员ID',
  `substitute_type` tinyint DEFAULT '1' COMMENT '替补类型:1-自动匹配,2-手动选择',
  PRIMARY KEY (`id`),
  KEY `assignment_id` (`assignment_id`),
  KEY `employee_id` (`employee_id`),
  KEY `idx_substitute_employee_id` (`substitute_employee_id`),
  CONSTRAINT `duty_record_ibfk_1` FOREIGN KEY (`assignment_id`) REFERENCES `duty_assignment` (`id`) ON DELETE CASCADE,
  CONSTRAINT `duty_record_ibfk_2` FOREIGN KEY (`employee_id`) REFERENCES `sys_employee` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_substitute_employee` FOREIGN KEY (`substitute_employee_id`) REFERENCES `sys_employee` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='值班记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

